const fs = require('fs');
const path = require('path');

class WebOSCore {
    constructor(root) {
        this.root = root;
        if (!fs.existsSync(root)) fs.mkdirSync(root);
    }

    setupUser(username) {
        const userPath = path.join(this.root, username);
        const subDirs = ['/fs', '/extensions', '/settings'];
        if (!fs.existsSync(userPath)) {
            fs.mkdirSync(userPath);
            subDirs.forEach(d => fs.mkdirSync(path.join(userPath, d)));
        }
        return { 
            path: userPath, 
            partition: `persist:user-${username}` 
        };
    }

    listUserFiles(username, subPath = 'fs') {
        const target = path.join(this.root, username, subPath);
        return fs.readdirSync(target).map(file => ({
            name: file,
            isDir: fs.statSync(path.join(target, file)).isDirectory()
        }));
    }
}

module.exports = WebOSCore;
